mapper.select:
SELECT m.id, m.room_id, m.plan_id, m.writer_id, u.nickname AS writer_nickname,
       u.profile_image_url AS writer_profile_image_url, m.title, m.content, m.memory_date,
       m.created_at, m.updated_at,
       (SELECT COUNT(*) FROM memory_comments c WHERE c.memory_id = m.id) AS comment_count,
       (SELECT GROUP_CONCAT(mt.tag SEPARATOR ',') FROM memory_tags mt WHERE mt.memory_id = m.id) AS tags_csv
FROM memories m
JOIN users u ON u.id = m.writer_id

    m.room_id = #{roomId} AND m.deleted_at IS NULL
    AND DATE_FORMAT(m.memory_date, '%Y-%m') = #{month}
    AND m.writer_id = #{writerId}
    AND EXISTS (
        SELECT 1 FROM memory_tags mt2 WHERE mt2.memory_id = m.id AND mt2.tag = #{tag}
    )
    AND EXISTS (
        SELECT 1 FROM memory_participants mp WHERE mp.memory_id = m.id AND mp.user_id = #{participantUserId}
    )

ORDER BY m.memory_date DESC, m.id DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE memories
title = #{request.title}, content = #{request.content}, memory_date = #{request.memoryDate},
WHERE id = #{memoryId}
